import React, { useEffect, useState } from 'react';
import { View, Text, Button } from 'react-native';
import { sensitiveDataService } from '../services/sensitiveDataService';

export default function ExampleUsage() {
  const [profile, setProfile] = useState(null);

  useEffect(() => {
    (async () => {
      const savedProfile = await sensitiveDataService.getUserProfile();
      setProfile(savedProfile);
    })();
  }, []);

  const handleSave = async () => {
    await sensitiveDataService.saveUserProfile({
      id: '123',
      name: 'Jane Doe',
      email: 'jane@example.com',
    });

    await sensitiveDataService.savePaymentInfo({
      cardHolder: 'Jane Doe',
      last4: '4242',
      brand: 'Visa',
    });

    await sensitiveDataService.saveAuthToken('sample-auth-token');
    const savedProfile = await sensitiveDataService.getUserProfile();
    setProfile(savedProfile);
  };

  const handleClear = async () => {
    await sensitiveDataService.clearSensitiveData();
    setProfile(null);
  };

  return (
    <View>
      <Text>{profile ? JSON.stringify(profile) : 'No profile stored'}</Text>
      <Button title="Save Sensitive Data" onPress={handleSave} />
      <Button title="Clear Sensitive Data" onPress={handleClear} />
    </View>
  );
}